import { mkdirSync, readFileSync, readdirSync, writeFileSync } from 'node:fs';
import path from 'node:path';

const projectRoot = process.cwd();
const sourceRoot = path.join(projectRoot, 'src');
const outputPath = path.join(projectRoot, 'generated', 'iconify-icons.ts');

const iconSetPackages = {
  'eos-icons': '@iconify-json/eos-icons',
  'ep': '@iconify-json/ep',
  'fluent': '@iconify-json/fluent',
  'heroicons': '@iconify-json/heroicons',
  'material-symbols': '@iconify-json/material-symbols',
  'mdi': '@iconify-json/mdi',
  'ph': '@iconify-json/ph',
  'qlementine-icons': '@iconify-json/qlementine-icons',
};

const iconPattern = /\b([a-z0-9]+(?:-[a-z0-9]+)*:[a-z0-9]+(?:-[a-z0-9]+)*)\b/g;
const sourceExtensions = new Set(['.ts', '.tsx', '.vue']);

const readJson = (filePath) => JSON.parse(readFileSync(filePath, 'utf8'));

const walkFiles = (dirPath) => {
  const entries = readdirSync(dirPath, { withFileTypes: true });
  const files = [];

  for (const entry of entries) {
    const entryPath = path.join(dirPath, entry.name);
    if (entry.isDirectory()) {
      files.push(...walkFiles(entryPath));
      continue;
    }

    if (sourceExtensions.has(path.extname(entry.name))) {
      files.push(entryPath);
    }
  }

  return files;
};

const collectUsedIcons = () => {
  const iconsByPrefix = new Map();

  for (const filePath of walkFiles(sourceRoot)) {
    const content = readFileSync(filePath, 'utf8');
    const matches = content.matchAll(iconPattern);

    for (const match of matches) {
      const iconName = match[1];
      const [prefix, name] = iconName.split(':');
      if (!prefix || !name || !(prefix in iconSetPackages)) {
        continue;
      }

      if (!iconsByPrefix.has(prefix)) {
        iconsByPrefix.set(prefix, new Set());
      }

      iconsByPrefix.get(prefix).add(name);
    }
  }

  return iconsByPrefix;
};

const cloneEntry = (entry) => JSON.parse(JSON.stringify(entry));

const buildCollection = (prefix, requestedNames) => {
  const packageName = iconSetPackages[prefix];
  const packagePath = path.join(projectRoot, 'node_modules', packageName, 'icons.json');
  const sourceCollection = readJson(packagePath);

  const icons = {};
  const aliases = {};
  const queue = [...requestedNames];
  const seen = new Set();

  while (queue.length > 0) {
    const currentName = queue.pop();
    if (!currentName || seen.has(currentName)) {
      continue;
    }
    seen.add(currentName);

    const iconData = sourceCollection.icons?.[currentName];
    if (iconData) {
      icons[currentName] = cloneEntry(iconData);
      continue;
    }

    const aliasData = sourceCollection.aliases?.[currentName];
    if (aliasData) {
      aliases[currentName] = cloneEntry(aliasData);
      if (aliasData.parent) {
        queue.push(aliasData.parent);
      }
      continue;
    }

    throw new Error(`Icon "${prefix}:${currentName}" was referenced in source but not found in ${packageName}.`);
  }

  const collection = {
    prefix: sourceCollection.prefix,
    icons,
  };

  for (const key of ['aliases', 'width', 'height', 'left', 'top']) {
    if (key === 'aliases') {
      if (Object.keys(aliases).length > 0) {
        collection.aliases = aliases;
      }
      continue;
    }

    if (key in sourceCollection) {
      collection[key] = sourceCollection[key];
    }
  }

  return collection;
};

const generateModule = (collections, iconNames) => {
  const banner = [
    '// This file is auto-generated by scripts/generate-iconify-bundle.mjs.',
    '// Do not edit it manually.',
    '',
    "import { addCollection } from '@iconify/vue';",
    '',
    `export const bundledIconNames = ${JSON.stringify(iconNames, null, 2)} as const;`,
    '',
    `const collections = ${JSON.stringify(collections, null, 2)} as const;`,
    '',
    'let iconifyIconsRegistered = false;',
    '',
    'export const registerBundledIconifyIcons = () => {',
    '  if (iconifyIconsRegistered) return;',
    '',
    '  for (const collection of collections) {',
    '    addCollection(collection);',
    '  }',
    '',
    '  iconifyIconsRegistered = true;',
    '};',
    '',
  ];

  return banner.join('\n');
};

const iconMap = collectUsedIcons();
const sortedPrefixes = [...iconMap.keys()].sort((left, right) => left.localeCompare(right));
const collections = [];
const bundledIconNames = [];

for (const prefix of sortedPrefixes) {
  const requestedNames = [...iconMap.get(prefix)].sort((left, right) => left.localeCompare(right));
  collections.push(buildCollection(prefix, requestedNames));
  for (const name of requestedNames) {
    bundledIconNames.push(`${prefix}:${name}`);
  }
}

mkdirSync(path.dirname(outputPath), { recursive: true });
writeFileSync(outputPath, generateModule(collections, bundledIconNames), 'utf8');

const relativeOutputPath = path.relative(projectRoot, outputPath);
console.log(`Generated ${relativeOutputPath} with ${bundledIconNames.length} Iconify icons.`);
